const item = $input.first();
let text = item.json.extracted_text || "";

// normalisation basique
text = text
  .replace(/\r/g, "\n")
  .replace(/\t/g, " ")
  .replace(/\u0000/g, " ")
  .replace(/[ ]{2,}/g, " ")
  .replace(/\n{3,}/g, "\n\n")
  .trim();

// fusion légère des lignes cassées
text = text
  .split("\n")
  .map(line => line.trim())
  .filter(line => line.length > 0)
  .join("\n");

return [
  {
    json: {
      ...item.json,
      clean_text: text
    }
  }
];

const item = $input.first();

const text = item.json.clean_text || "";
const chunkSize = 1200;   // taille approximative en caractères
const overlap = 200;      // recouvrement entre chunks

if (!text.trim()) {
  return [];
}

const chunks = [];
let start = 0;
let index = 0;

while (start < text.length) {
  let end = start + chunkSize;

  if (end < text.length) {
    const lastSpace = text.lastIndexOf(" ", end);
    if (lastSpace > start + 200) {
      end = lastSpace;
    }
  }

  const chunkText = text.slice(start, end).trim();

  if (chunkText) {
    chunks.push({
      json: {
        job_id: item.json.job_id,
        tenant_id: item.json.tenant_id,
        filename: item.json.filename,
        storage_key: item.json.storage_key,
        chunk_index: index,
        chunk_text: chunkText
      }
    });
    index++;
  }

  const nextStart = end - overlap;
  start = nextStart > start ? nextStart : end;

}

return chunks;

const item = $input.first();
const file = item.binary?.data;

const errors = [];
const maxSizeMB = 50;
const maxSizeBytes = maxSizeMB * 1024 * 1024;

/**
 * Convertit "13.7 kB" → bytes
 */
function parseFileSizeToBytes(value) {
  if (typeof value === "number") return value;

  if (!value || typeof value !== "string") return NaN;

  const normalized = value.trim().toLowerCase();
  const match = normalized.match(/^([\d.]+)\s*(b|kb|kib|mb|mib|gb|gib)?$/);

  if (!match) return NaN;

  const number = parseFloat(match[1]);
  const unit = match[2] || "b";

  const multipliers = {
    b: 1,
    kb: 1024,
    kib: 1024,
    mb: 1024 * 1024,
    mib: 1024 * 1024,
    gb: 1024 * 1024 * 1024,
    gib: 1024 * 1024 * 1024
  };

  return number * multipliers[unit];
}

if (!file) {
  errors.push("Aucun fichier reçu dans $binary.data");
}

const fileName = file?.fileName || "";
const mimeType = file?.mimeType || "";

// ✅ ICI on remplace Number() par ta fonction
const fileSizeRaw = file?.fileSize;
const fileSize = parseFileSizeToBytes(fileSizeRaw);

if (file) {
  if (!fileName) {
    errors.push("Nom de fichier manquant");
  }

  if (!fileName.toLowerCase().endsWith(".pdf")) {
    errors.push("Extension invalide: seul .pdf est accepté");
  }

  if (!mimeType || !mimeType.toLowerCase().includes("pdf")) {
    errors.push(`Type MIME invalide: ${mimeType || "inconnu"}`);
  }

  if (!Number.isFinite(fileSize)) {
    errors.push(`Taille fichier invalide: ${fileSizeRaw}`);
  }

  if (Number.isFinite(fileSize) && fileSize <= 0) {
    errors.push("Taille fichier égale à 0");
  }

  if (Number.isFinite(fileSize) && fileSize > maxSizeBytes) {
    errors.push(`Fichier trop lourd: limite ${maxSizeMB}MB`);
  }
}

return [
  {
    json: {
      ...item.json,
      fileName,
      mimeType,
      fileSize,
      tenant_id: item.json.tenant_id || "tenant-a",
      is_valid_file: errors.length === 0,
      error_message: errors.join(" | "),
      validation_errors: errors
    },
    binary: item.binary
  }
];

